  <div class="fr">
  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;min-width:520px;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="24" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Changements de consensus de Bitcoin et proposition d'activation CTV/CSFS</text>
    <text x="24" y="56" fill="#a1a1aa" font-size="13" font-family="sans-serif">Tentatives d'activation de soft fork et résultats · Source : Bitcoin Optech, Bitcoin Magazine</text>
    <line x1="40" y1="90" x2="40" y2="300" stroke="#3f3f46" stroke-width="2"/>
    <circle cx="40" cy="110" r="6" fill="#22c55e"/><text x="60" y="108" fill="#e4e4e7" font-size="14" font-family="sans-serif" font-weight="700">2017 · SegWit</text><text x="60" y="126" fill="#a1a1aa" font-size="13" font-family="sans-serif">Activé après la pression de l'UASF (BIP148)</text>
    <circle cx="40" cy="160" r="6" fill="#22c55e"/><text x="60" y="158" fill="#e4e4e7" font-size="14" font-family="sans-serif" font-weight="700">2021 · Taproot</text><text x="60" y="176" fill="#a1a1aa" font-size="13" font-family="sans-serif">Fluide via Speedy Trial (consensus présent)</text>
